/* Media query */
@media screen and (max-width: 768px) {

.burger {
    display: flex;
    cursor: pointer;
  }

.burger #closeHam {
    display: none;
  }

.nav-items {
    display: none;
    flex-direction: column;
    align-items: center;
    position: absolute;
    right: 0;
    top: 58px;
    background-color: var(--nav-colour);
    width: 100%;
    height: calc(100vh - 58px);
    padding-top: 60px;
    gap: 10vh;
  }
}

